const deadCandidates = (liveCells: Cell[]): Cell[] => {
  const candidates: Cell[] = [];
  for (const cell of liveCells) {
    const [cx, cy] = cell;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const neighbor: Cell = [cx + dx, cy + dy];
        if (!liveCells.some(([lx, ly]) => lx === neighbor[0] && ly === neighbor[1])) {
          if (!candidates.some(([px, py]) => px === neighbor[0] && py === neighbor[1])) {
            candidates.push(neighbor);
          }
        }
      }
    }
  }
  return candidates;
};

export const evolve = (liveCells: Cell[]): Cell[] => {
  const survivors = liveCells.filter((cell) => {
    const neighbors = neighborCount(cell, liveCells);
    return neighbors === 2 || neighbors === 3;
  });
  const born = deadCandidates(liveCells).filter(
    (cell) => neighborCount(cell, liveCells) === 3
  );
  return [...survivors, ...born];
};

